module top_module( clk, d, q, r);input  clk;
	input  d;
  input  r;
	output q;  

  reg q_reg;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or negedge r or posedge dbg_halt) begin
		if(!r)
      q_reg <= 1'b0;
    else 
      q_reg <= d;

  end

assign q = q_reg;endmodule
